623→  async extractAttachments(baileysMsg, normalizedMessage) {
624→    const attachments = [];
625→    if (!normalizedMessage) return attachments;
626→
627→    if (normalizedMessage.imageMessage) {
628→      const buffer = await downloadMediaMessage(
629→        baileysMsg,
630→        "buffer",
631→        {},
632→        { logger: pino({ level: "silent" }) },
