 25→export function createVisionTool({ config, logger }) {
 26→  async function extractScoresFromImage({ imagePath, suggestedClassFile }) {
 27→    const imageBuffer = await fs.readFile(imagePath);
 28→    const base64Image = imageBuffer.toString("base64");
 29→
 30→    const prompt = [
 31→      "/no_think",
 32→      "Extract a score sheet from this image.",
 33→      "Return strict JSON ONLY with this structure:",
 34→      '{ "classFile": "optional_filename.xlsx", "rows": [{"student":"Name","score":95}], "warnings": ["..."] }',
 35→      "Rules:",
 36→      "- student must be non-empty string",
 37→      "- score must be numeric",
 38→      "- do not invent missing scores",
 39→      "- if uncertain, add warning",
 40→      `- preferred class file if known: ${suggestedClassFile || "class1.xlsx"}`,
 41→    ].join("\n");
 42→
 43→    const doRequest = async () => {
 44→      const response = await postOllamaChat({
 45→        baseUrl: config.ollama.baseUrl,
 46→        model: config.ollama.model,
 47→        timeoutMs: config.ollama.requestTimeoutMs,
 48→        logger,
 49→        stream: false,
 50→        messages: [
 51→          {
 52→            role: "user",
 53→            content: prompt,
 54→            images: [base64Image],
 55→          },
 56→        ],
 57→      });
 58→      const content = response?.data?.message?.content;
 59→      if (!content) {
 60→        throw new Error("Ollama vision response is missing content.");
 61→      }
 62→      return parseModelJson(content);
 63→    };
 64→
 65→    const parsed = await pRetry(doRequest, {
 66→      retries: Math.max(0, (config.ollama.retries || 1) - 1),
 67→      factor: 2,
 68→      minTimeout: 800,
 69→      maxTimeout: 5000,
 70→      onFailedAttempt: (error) => {
 71→        logger.warn(
 72→          `Vision retry ${error.attemptNumber} failed: ${error.message}`,
 73→        );
 74→      },
 75→    });
 76→
 77→    const rawRows = Array.isArray(parsed.rows) ? parsed.rows : [];
 78→    const rows = [];
 79→    const warnings = Array.isArray(parsed.warnings) ? [...parsed.warnings] : [];
 80→
 81→    for (const row of rawRows) {
 82→      const student = String(row?.student || "").trim();
 83→      const score = Number(row?.score);
 84→      if (!student) {
 85→        warnings.push("A row was skipped because student name was missing.");
 86→        continue;
 87→      }
 88→      if (!validateScore(score, config.limits.minScore, config.limits.maxScore)) {
 89→        warnings.push(
 90→          `A row for "${student}" was skipped because score ${row?.score} is outside 0-100.`,
 91→        );
 92→        continue;
 93→      }
 94→      rows.push({ student, score });
 95→    }
 96→
 97→    return {
 98→      classFile: parsed.classFile || suggestedClassFile || "class1.xlsx",
 99→      rows,
100→      warnings,
101→      raw: parsed,
102→    };
103→  }
104→
105→  return { extractScoresFromImage };
106→}
