 3→function normalizeBaseUrl(baseUrl) {
 4→  return String(baseUrl || "").replace(/\/+$/, "");
 5→}
 6→
 7→function toIpv4Localhost(baseUrl) {
 8→  const normalized = normalizeBaseUrl(baseUrl);
 9→  return normalized.replace("://localhost", "://127.0.0.1");
10→}
11→
12→function isIpv6Refused(error) {
13→  const message = String(error?.message || "");
14→  const code = String(error?.code || "");
15→  return (
16→    code === "ECONNREFUSED" ||
17→    message.includes("ECONNREFUSED ::1") ||
18→    message.includes("::1:11434")
19→  );
20→}
21→
22→export async function postOllamaChat({
23→  baseUrl,
24→  model,
25→  messages,
26→  timeoutMs,
27→  logger,
28→  stream = false,
29→}) {
30→  const primaryBase = normalizeBaseUrl(baseUrl);
31→  const primaryUrl = `${primaryBase}/api/chat`;
32→  const payload = {
33→    model,
34→    stream,
35→    messages,
36→  };
37→
38→  try {
39→    return await axios.post(primaryUrl, payload, { timeout: timeoutMs });
40→  } catch (error) {
41→    const fallbackBase = toIpv4Localhost(primaryBase);
42→    if (fallbackBase !== primaryBase && isIpv6Refused(error)) {
43→      const fallbackUrl = `${fallbackBase}/api/chat`;
44→      logger?.warn?.(
45→        `Ollama localhost IPv6 connection failed. Retrying with IPv4 endpoint ${fallbackBase}.`,
46→      );
47→      return axios.post(fallbackUrl, payload, { timeout: timeoutMs });
48→    }
49→    throw error;
50→  }
51→}
